/* eslint-disable max-len */
import { StorageService, storageService } from ".";
import { initializeFirebase } from "../../../../__tests__/helpers/firebase";
import { storage } from "../../../infrastructure";
import { Exception } from "../../../lib";

describe("StorageService", () => {
  beforeAll(() => {
    initializeFirebase();
  });

  describe("storageService instance", () => {
    test("should be an instance of StorageService", () => {
      expect(storageService).toBeInstanceOf(StorageService);
    });
  });

  describe("storageService methods", () => {
    afterEach(() => {
      jest.resetAllMocks();
    });

    const dataUri =
      "data:image/jpeg;base64,";

    const path = "users/profile-picture";

    describe("transformDataUriToAcceptedFormatForStorage", () => {
      test("should throw a server error if uri is not provided", () => {
        expect(
          storageService.transformDataUriToAcceptedFormatForStorage(""),
        ).toThrow(Exception);
      });

      test("should return null if the datauri is not valid", () => {
        const res =
          storageService.transformDataUriToAcceptedFormatForStorage("1234");

        expect(res).toBeNull();
      });

      test("should return the transformed data", () => {
        const res =
          storageService.transformDataUriToAcceptedFormatForStorage(dataUri);

        expect(res).toHaveProperty("body");
        expect(res).toHaveProperty("mimeType", "image/jpeg");
        expect(res?.body).toBeInstanceOf(Buffer);
      });
    });

    describe("getMimeTypeFromExtension", () => {
      test("should throw a server error if fileExtension is not provided", () => {
        expect(storageService.getMimeTypeFromExtension("")).toThrow(Exception);
      });

      test("should return null if passed an invalid file extension", () => {
        const res = storageService.getMimeTypeFromExtension("1234");

        expect(res).toBeNull();
      });

      test("should return image/jpeg when passed in file extension 'jpeg'", () => {
        const mimeType = storageService.getMimeTypeFromExtension("jpeg");
        expect(mimeType).toEqual("image/jpeg");
      });
    });

    describe("getFileExtensionFromMimeType", () => {
      test("should throw a server error if mimeType is not provided", () => {
        expect(storageService.getFileExtensionFromMimeType("")).toThrow(
          Exception,
        );
      });

      test("should return null if passed an invalid mimeType", () => {
        const res = storageService.getFileExtensionFromMimeType("foo/txt");

        expect(res).toBeNull();
      });

      test("should return json when passed in mime type 'application/json'", () => {
        const fileExtension =
          storageService.getFileExtensionFromMimeType("application/json");
        expect(fileExtension).toEqual("json");
      });
    });

    describe("saveObject", () => {
      test("should throw an error if not no datauri or an invalid path is passed", async () => {
        expect(await storageService.saveObject("", path)).toThrow(Exception);
        expect(await storageService.saveObject("1234", path)).toThrow(
          Exception,
        );
        expect(await storageService.saveObject(dataUri, "")).toThrow(Exception);
        expect(await storageService.saveObject(dataUri, "1234")).toThrow(
          Exception,
        );
      });

      test("should pass", async () => {
        const storageReturnData = {
          mimeType: "image/jpeg",
          path,
          url: "https://images.pexels.com/photos/5641953/pexels-photo-5641953.jpeg?auto=compress&cs=tinysrgb&w=600&lazy=load",
        };

        const spy = jest
          .spyOn(storage, "put")
          .mockImplementation(async () => storageReturnData);

        const res = await storageService.saveObject(dataUri, path);
        expect(spy).toHaveBeenCalled();
        expect(res).toEqual(storageReturnData);
      });
    });

    describe("deleteObject", () => {
      test("should throw an error if not no or invalid path is passed", async () => {
        expect(await storageService.saveObject(dataUri, "")).toThrow(Exception);
        expect(await storageService.saveObject(dataUri, "1234")).toThrow(
          Exception,
        );
      });

      test("should pass", async () => {
        const spy = jest.spyOn(storage, "delete").mockImplementation();
        await storageService.deleteObject(path);
        expect(spy).toHaveBeenCalled();
      });
    });
  });
});
